1651 static Constant *constantFoldOperationIntoSelectOperand(Instruction &I,
1652                                                         SelectInst *SI,
1653                                                         bool IsTrueArm) {
1654   SmallVector<Constant *> ConstOps;
1655   for (Value *Op : I.operands()) {
1656     Constant *C = nullptr;
1657     if (Op == SI) {
1658       C = dyn_cast<Constant>(IsTrueArm ? SI->getTrueValue()
1659                                        : SI->getFalseValue());
1660     } else if (match(SI->getCondition(),
1661                      m_SpecificICmp(IsTrueArm ? ICmpInst::ICMP_EQ
1662                                               : ICmpInst::ICMP_NE,
1663                                     m_Specific(Op), m_Constant(C))) &&
1664                isGuaranteedNotToBeUndefOrPoison(C)) {
1665       // Pass
1666     } else {
1667       C = dyn_cast<Constant>(Op);
1668     }
1669     if (C == nullptr)
1670       return nullptr;
1671 
1672     ConstOps.push_back(C);
1673   }
1674 
1675   return ConstantFoldInstOperands(&I, ConstOps, I.getDataLayout());
1676 }
