1678 static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
1679                                              Value *NewOp, InstCombiner &IC) {
1680   Instruction *Clone = I.clone();
1681   Clone->replaceUsesOfWith(SI, NewOp);
1682   Clone->dropUBImplyingAttrsAndMetadata();
1683   IC.InsertNewInstBefore(Clone, SI->getIterator());
1684   return Clone;
